#!/usr/bin/env python3
"""harness-scaffold — scaffold a loss-function harness tree.

Reads a /goal prompt, extracts the structured sections, and
writes the matching project tree at the project root. See
SKILL.md for the contract.

Usage:
  harness-scaffold --project-root PATH [--goal-prompt PATH] \
                   [--runtime {cline|codex|aider}] [--no-private]
"""
from __future__ import annotations

import argparse
import os
import re
import stat
import sys
from pathlib import Path
from textwrap import dedent

GENERATED_HEADER = (
    "# auto-generated by harness-scaffold v1.0\n"
    "# DO NOT EDIT — re-run `harness-scaffold` to regenerate\n"
    "# (this header marker is how the scaffold detects safe-to-overwrite files)\n"
)

AGENT_EDITED_MARKER = "# agent-edited: yes"


def is_user_edited(path):
    if not path.exists():
        return False
    try:
        with path.open() as f:
            head = "".join(f.readline() for _ in range(5))
    except Exception:
        return False
    return AGENT_EDITED_MARKER in head


def safe_write(path, content, executable=False):
    if is_user_edited(path):
        print("  skip (user-edited): " + str(path), file=sys.stderr)
        return
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w") as f:
        f.write(content)
    if executable:
        path.chmod(path.stat().st_mode | stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH)
    print("  write: " + str(path), file=sys.stderr)


def chmod_700(path):
    if path.exists():
        path.chmod(0o700)


def chmod_600(path):
    if path.exists():
        path.chmod(0o600)


def extract_design_tasks(prompt):
    m = re.search(r"Design-set tasks.*?\n\n(.*?)(?=\n\n#|\Z)", prompt, re.S)
    if not m:
        return []
    block = m.group(1)
    tasks = []
    for line in block.splitlines():
        line = line.strip()
        m2 = re.match(r"^\d+\.\s+(.+)$", line)
        if not m2:
            continue
        desc = m2.group(1).strip()
        if "`" in desc:
            em = max(desc.rfind(" — "), desc.rfind(" - "))
            if em > 0:
                desc = desc[em + 3:].strip()
            else:
                m3 = re.match(r"^`[^`]+`\s*(.*)$", desc)
                if m3:
                    desc = m3.group(1).strip()
        desc = desc.strip("`'\"")
        tasks.append(desc)
    return tasks


def extract_held_out_tasks(prompt):
    m = re.search(r"Held-out tasks.*?\n\n(.*?)(?=\n\n#|\Z)", prompt, re.S)
    if not m:
        return [f"h{i:02d}" for i in range(1, 11)]
    block = m.group(1)
    range_match = re.search(
        r"(h\d{2})[^a-zA-Z0-9]{1,8}(?:…|\.{2,}|—|–|through|to| - )[^a-zA-Z0-9]{1,8}(h\d{2})",
        block, re.I,
    )
    if range_match:
        try:
            a = int(range_match.group(1)[1:])
            b = int(range_match.group(2)[1:])
            if a > b:
                a, b = b, a
            return [f"h{n:02d}" for n in range(a, b + 1)]
        except Exception:
            pass
    explicit = re.findall(r"\b(h\d{2})\b", block)
    if explicit:
        seen = set()
        out = []
        for h in explicit:
            if h not in seen:
                seen.add(h)
                out.append(h)
        return out
    return [f"h{i:02d}" for i in range(1, 11)]


def extract_runtime(prompt):
    m = re.search(r"inner loop is the `(\w+)` CLI", prompt)
    return m.group(1) if m else "cline"


def slugify(s):
    s = s.lower()
    s = re.sub(r"[^a-z0-9\s-]", "", s)
    s = re.sub(r"\s+", "-", s)
    s = re.sub(r"-+", "-", s)
    return s.strip("-")


def word_truncate(s, max_len):
    """Truncate at word boundary, max max_len chars."""
    if len(s) <= max_len:
        return s
    truncated = s[:max_len]
    # Find last hyphen
    last_hyphen = truncated.rfind("-")
    if last_hyphen > max_len // 2:
        return truncated[:last_hyphen]
    return truncated


INTEGRITY_SH = (
    GENERATED_HEADER
    + "#!/usr/bin/env bash\n"
    + "# verifiers/integrity.sh — anti-cheat guards. Runs BEFORE every\n"
    + "# design-set cycle. Exits 0 if the harness is intact, non-zero\n"
    + "# if any guard fires.\n"
    + "#\n"
    + "# Default guards cover the 5 cheats from BUILDING-A-GREAT-HARNESS.md\n"
    + "# V0-7: test deletion, stub-always-passes, sleep-to-pass, rules-file\n"
    + "# modification, hidden-dir read. Replace with project-specific guards\n"
    + "# before the /goal prompt is emitted.\n"
    + "#\n"
    + "# Usage: integrity.sh [--help] [--project-root PATH]\n"
    + "#   (no flag):  report. exit 0 if all guards pass, 1 if any fail.\n"
    + "#   --project-root PATH: override the auto-detected project root.\n"
    + "#   --help:     show this help and exit 0.\n"
    + "#\n"
    + "# Project root is auto-detected from this script's location\n"
    + "# (../.. from verifiers/integrity.sh). The $PROJECT_DIR env var\n"
    + "# overrides it; --project-root overrides the env var.\n"
    + "\n"
    + "set -euo pipefail\n"
    + "\n"
    + 'SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"\n'
    + 'DEFAULT_PROJECT_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)"\n'
    + 'PROJECT_DIR="${PROJECT_DIR:-$DEFAULT_PROJECT_ROOT}"\n'
    + "\n"
    + "while [[ $# -gt 0 ]]; do\n"
    + '  case "$1" in\n'
    + '    --help|-h)\n'
    + '      sed -n "2,/^[^#]/{/^[^#]/q; p}" "$0" | sed "s/^# \\{0,1\\}//"\n'
    + "      exit 0\n"
    + "      ;;\n"
    + '    --project-root) PROJECT_DIR="$2"; shift 2 ;;\n'
    + '    *) echo "unknown flag: $1" >&2; exit 2 ;;\n'
    + "  esac\n"
    + "done\n"
    + "\n"
    + "[[ -d \"$PROJECT_DIR\" ]] || { echo \"integrity: project root not found: $PROJECT_DIR\" >&2; exit 2; }\n"
    + "\n"
    + "FAILS=0\n"
    + "REPORT=\"\"\n"
    + "\n"
    + "check() {\n"
    + '  local name="$1"; shift\n'
    + '  if "$@"; then\n'
    + '    REPORT+="ok    ${name}\n"\n'
    + "  else\n"
    + '    REPORT+="FAIL  ${name}\n"\n'
    + "    FAILS=$((FAILS + 1))\n"
    + "  fi\n"
    + "}\n"
    + "\n"
    + "# ----- guards (project-specific) -----\n"
    + "\n"
    + "guard_no_grade_todo_stub() {\n"
    + '  local d="$PROJECT_DIR/test-tasks/design"\n'
    + '  [[ -d "$d" ]] || return 0\n'
    + '  local g\n'
    + '  while IFS= read -r g; do\n'
    + '    if grep -qE "TODO.*grade|TODO.*meta-fill" "$g" 2>/dev/null; then\n'
    + "      return 1\n"
    + "    fi\n"
    + "  done < <(find \"$d\" -name grade.sh 2>/dev/null)\n"
    + "  return 0\n"
    + "}\n"
    + "\n"
    + "guard_no_stub_always_pass() {\n"
    + '  local d="$PROJECT_DIR/test-tasks/design"\n'
    + '  [[ -d "$d" ]] || return 0\n'
    + '  local g\n'
    + '  while IFS= read -r g; do\n'
    + '    if ! grep -qE "(\\btest\\b|\\bassert\\b|\\bgrep\\b|\\bdiff\\b|\\bjq\\b|\\bpytest\\b|\\bgo test\\b|\\bnode -e\\b|\\bbash -c\\b|\\bpython3? -c\\b|\\bpython3? -)" "$g" 2>/dev/null; then\n'
    + "      return 1\n"
    + "    fi\n"
    + "  done < <(find \"$d\" -name grade.sh 2>/dev/null)\n"
    + "  return 0\n"
    + "}\n"
    + "\n"
    + "guard_no_sleep_in_grader() {\n"
    + '  local d="$PROJECT_DIR/test-tasks/design"\n'
    + '  [[ -d "$d" ]] || return 0\n'
    + '  local g\n'
    + '  while IFS= read -r g; do\n'
    + '    if grep -qE "time\\.Sleep|\\bsleep [0-9]" "$g" 2>/dev/null; then\n'
    + "      return 1\n"
    + "    fi\n"
    + "  done < <(find \"$d\" -name grade.sh 2>/dev/null)\n"
    + "  return 0\n"
    + "}\n"
    + "\n"
    + "guard_agents_md_has_hard_rules() {\n"
    + '  local f="$PROJECT_DIR/AGENTS.md"\n'
    + '  [[ -f "$f" ]] || return 1\n'
    + '  grep -q "DO NOT read .*verifiers/private" "$f" \\\n'
    + '    && grep -q "DO NOT read .*test-tasks/held-out" "$f"\n'
    + "}\n"
    + "\n"
    + "\n"
    + 'printf "%s" "$REPORT"\n'
    + 'if [[ "$FAILS" -gt 0 ]]; then\n'
    + '  echo "" >&2\n'
    + '  echo "integrity: $FAILS guard(s) failed" >&2\n'
    + "  exit 1\n"
    + "fi\n"
    + 'echo "integrity: all guards pass"\n'
    + "exit 0\n"
)


