COMPUTE_SUB_LOSSES_STUB = (
    GENERATED_HEADER
    + "#!/usr/bin/env python3\n"
    + '"""Per-cycle sub-loss scorer stub. Replace with the full\n'''
    "implementation from the cline-orchestration skill's references/\n"
    "directory, or implement your own 7 sub-losses using the\n"
    "WEIGHTS / GATES constants below as a starting point.\n"
    '"""\n'
    + "from __future__ import annotations\n"
    + "import json, sys\n"
    + "from pathlib import Path\n"
    + "\n"
    + "WEIGHTS = {\n"
    + '    "correctness": 1.0,\n'
    + '    "performance": 0.5,\n'
    + '    "safety": 1.0,\n'
    + '    "legibility": 0.3,\n'
    + '    "invariants": 1.0,\n'
    + '    "drift": 0.2,\n'
    + '    "cost": 0.3,\n'
    + "}\n"
    + 'GATES = {"correctness", "safety", "invariants"}\n'
    + "\n"
    + "def main(path):\n"
    + "    p = Path(path)\n"
    + "    if not p.exists():\n"
    + '        print(json.dumps({"error": f"cycle json not found: {path}"}))\n'
    + "        return\n"
    + "    raw = {}\n"
    + "    try:\n"
    + "        raw = json.loads(p.read_text())\n"
    + "    except json.JSONDecodeError:\n"
    + "        for line in p.read_text().splitlines():\n"
    + "            try:\n"
    + "                obj = json.loads(line.strip())\n"
    + '                if obj.get("type") == "run_result":\n'
    + '                    agg = obj.get("aggregateUsage") or {}\n'
    + "                    raw = {\n"
    + '                        "tokens": int(agg.get("inputTokens", 0) or 0) + int(agg.get("outputTokens", 0) or 0),\n'
    + '                        "elapsed_seconds": int(obj.get("durationMs", 0) or 0) // 1000,\n'
    + '                        "finish_reason": obj.get("finishReason", ""),\n'
    + '                        "exit_code": 0,\n'
    + '                        "candidate_text": obj.get("text", ""),\n'
    + '                        "model": (obj.get("model") or {}).get("id", ""),\n'
    + "                    }\n"
    + "                    break\n"
    + "            except json.JSONDecodeError:\n"
    + "                continue\n"
    + "    scores = {\n"
    + '        "correctness": 1.0 if raw.get("exit_code") == 0 and raw.get("candidate_text", "").strip() else 0.0,\n'
    + '        "performance": 1.0 if raw.get("elapsed_seconds", 999) <= 90 else 0.0,\n'
    + '        "safety": 1.0,\n'
    + '        "legibility": 1.0 if len(raw.get("candidate_text", "")) >= 10 else 0.3,\n'
    + '        "invariants": 1.0 if raw.get("exit_code") == 0 and raw.get("finish_reason") == "completed" else 0.0,\n'
    + '        "drift": 1.0,\n'
    + '        "cost": 1.0 if raw.get("tokens", 0) <= 4000 else 0.0,\n'
    + "    }\n"
    + '    out = {"sub_losses": {k: {"score": v, "details": {}} for k, v in scores.items()},\n'
    + '           "weights": WEIGHTS, "gates": list(GATES),\n'
    + '           "weighted_sum": sum(scores[k] * WEIGHTS[k] for k in scores),\n'
    + '           "weighted_total": sum(WEIGHTS.values()),\n'
    + '           "gates_passed": all(scores[g] >= 1.0 for g in GATES)}\n'
    + '    out["weighted_normalized"] = round(out["weighted_sum"] / out["weighted_total"], 4)\n'
    + "    print(json.dumps(out, indent=2))\n"
    + "\n"
    + 'if __name__ == "__main__":\n'
    + "    if len(sys.argv) < 2:\n"
    + '        print("usage: compute_sub_losses.py <cycle-N.json>", file=sys.stderr)\n'
    + "        sys.exit(2)\n"
    + "    main(sys.argv[1])\n"
)

CLINE_WRAPPER_SH = (
    GENERATED_HEADER
    + "#!/usr/bin/env bash\n"
    + "# cline-wrapper.sh — the ONLY way to invoke cline inside\n"
    + "# the loss loop.\n"
    + "#\n"
    + "# Usage:\n"
    + '#   verifiers/cline-wrapper.sh "<task-prompt>" --cwd PATH \\\n'
    + "#       --timeout 600 --cycle cycle-1 > cycle-1.json\n"
    + "#\n"
    + "# Why these flags:\n"
    + "# - --thinking none: many OpenAI-compat endpoints reject\n"
    + "#   the reasoning-token request shape. Change per provider.\n"
    + "# - --auto-approve true: required for non-interactive file\n"
    + "#   work. Safety is enforced by a separate transcript grep.\n"
    + "# - No --worktree: per-cycle directory already gives\n"
    + "#   isolation; --worktree triggers auth failures.\n"
    + "\n"
    + "set -euo pipefail\n"
    + "\n"
    + 'TASK=""; CWD=""; TIMEOUT=600; CYCLE="cycle-0"\n'
    + "while [[ $# -gt 0 ]]; do\n"
    + '  case "$1" in\n'
    + '    --cwd) CWD="$2"; shift 2 ;;\n'
    + '    --timeout) TIMEOUT="$2"; shift 2 ;;\n'
    + '    --cycle)\n'
    + '      if [[ "${2:-}" =~ ^[0-9]+$ ]]; then CYCLE="cycle-$2"; shift 2\n'
    + '      else CYCLE="${2:-cycle-0}"; shift 2; fi ;;\n'
    + '    --cycle=*) CYCLE="${1#--cycle=}"; shift ;;\n'
    + '    *) TASK="$1"; shift ;;\n'
    + "  esac\n"
    + "done\n"
    + '[[ -z "$TASK" || -z "$CWD" ]] && {\n'
    + '  echo \'{"error":"missing arg"}\' >&2; exit 2;\n'
    + "}\n"
    + "\n"
    + '# Resolve cline binary: $CLINE_BIN env, then PATH, then bail.\n'
    + 'CLINE_BIN="${CLINE_BIN:-$(command -v cline 2>/dev/null || true)}"\n'
    + '[[ -z "$CLINE_BIN" || ! -x "$CLINE_BIN" ]] && {\n'
    + '  echo \'{"error":"cline not found"}\' >&2; exit 3;\n'
    + "}\n"
    + "\n"
    + 'ITER_DIR="${CWD}/.iterations/${CYCLE}"\n'
    + 'mkdir -p "$ITER_DIR"\n'
    + "\n"
    + "# Seed the iter dir with the task's source files (so Cline\n"
    + "# has the actual problem to work on).\n"
    + "if command -v rsync >/dev/null 2>&1; then\n"
    + '  rsync -a --exclude=".iterations/" --exclude=".git/" \\\n'
    + '        --exclude="*.stderr" --exclude="cline.json" \\\n'
    + '        --exclude="cycle-summary.json" \\\n'
    + '        "$CWD"/ "$ITER_DIR"/ 2>/dev/null || true\n'
    + "else\n"
    + '  find "$CWD" -mindepth 1 -maxdepth 1 \\\n'
    + '       -not -name ".iterations" -not -name ".git" \\\n'
    + '       -exec cp -R {} "$ITER_DIR"/ \\; 2>/dev/null || true\n'
    + "fi\n"
    + "\n"
    + "START_TS=$(date +%s)\n"
    + 'RAW_OUT="${ITER_DIR}/cline.json"\n'
    + "EXIT_CODE=0\n"
    + "\n"
    + '"$CLINE_BIN" "$TASK" \\\n'
    + '  --cwd "$ITER_DIR" \\\n'
    + '  --auto-approve true \\\n'
    + '  --thinking none \\\n'
    + '  --json \\\n'
    + '  > "$RAW_OUT" 2>"${ITER_DIR}/cline.stderr" || EXIT_CODE=$?\n'
    + "\n"
    + "END_TS=$(date +%s)\n"
    + "ELAPSED=$((END_TS - START_TS))\n"
    + "\n"
    + 'SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"\n'
    + 'PARSED=$(python3 "$SCRIPT_DIR/parse_cline_output.py" "$RAW_OUT")\n'
    + "\n"
    + "python3 -c '\n"
    + "import json, sys\n"
    + "out = json.loads(sys.argv[1])\n"
    + 'out.update({\n'
    + '    "cycle": sys.argv[2],\n'
    + '    "exit_code": int(sys.argv[3]),\n'
    + '    "elapsed_seconds": int(sys.argv[4]),\n'
    + '    "raw_output_path": sys.argv[5],\n'
    + "})\n"
    + 'print(json.dumps(out, indent=2))\n'
    + "' \"$PARSED\" \"$CYCLE\" \"$EXIT_CODE\" \"$ELAPSED\" \"$RAW_OUT\"\n"
)

RUN_DESIGN_SET_SH = lambda design_task_names: (
    GENERATED_HEADER
    + "#!/usr/bin/env bash\n"
    + "# verifiers/run-design-set.sh\n"
    + "# Run the wrapper + per-task grader for every design task\n"
    + "# and emit an aggregate JSON score.\n"
    + "\n"
    + "set -euo pipefail\n"
    + 'PROJECT_DIR="${PROJECT_DIR:-$(pwd)}"\n'
    + 'CYCLE="${CYCLE:-design-set-cycle-$(date +%s)}"\n'
    + 'RUNS_DIR="$PROJECT_DIR/logs/design-set-runs/$CYCLE"\n'
    + 'SCORE_FILE="$PROJECT_DIR/logs/design-set-score.json"\n'
    + 'mkdir -p "$RUNS_DIR"\n'
    + "\n"
    + "TASKS=(\n"
    + "".join('  "%s"\n' % t for t in design_task_names)
    + ")\n"
    + "\n"
    + "n_pass=0; n_total=0; total_tokens=0\n"
    + "results=()\n"
    + "\n"
    + "for task in \"${TASKS[@]}\"; do\n"
    + "  n_total=$((n_total + 1))\n"
    + '  task_dir="$PROJECT_DIR/test-tasks/design/$task"\n'
    + '  task_run_dir="$RUNS_DIR/$task"\n'
    + '  mkdir -p "$task_run_dir"\n'
    + "\n"
    + '  if [[ ! -d "$task_dir" ]]; then\n'
    + '    results+=("{\\"task\\":\\"$task\\",\\"status\\":\\"missing\\",\\"detail\\":\\"no task dir\\"}")\n'
    + "    continue\n"
    + "  fi\n"
    + "\n"
    + '  if [[ -f "$task_dir/prompt.txt" ]]; then\n'
    + '    prompt="$(cat "$task_dir/prompt.txt")"\n'
    + "  else\n"
    + '    prompt="Look at the files in this directory and complete the task described in the README."\n'
    + "  fi\n"
    + "\n"
    + '  iter_dir="$task_dir/.iterations/$CYCLE"\n'
    + '  mkdir -p "$iter_dir"\n'
    + '  task_cycle="cycle-$(date +%s)-$task"\n'
    + "\n"
    + '  echo "[run-design-set] running wrapper for $task ..." >&2\n'
    + '  if "$PROJECT_DIR/verifiers/cline-wrapper.sh" "$prompt" \\\n'
    + '       --cwd "$task_dir" --timeout 180 --cycle "$task_cycle" \\\n'
    + '       > "$task_run_dir/cycle-summary.json" 2>"$task_run_dir/wrapper.stderr"; then\n'
    + "    :\n"
    + "  else\n"
    + '    echo "[run-design-set] wrapper failed for $task (exit $?)" >&2\n'
    + "  fi\n"
    + "\n"
    + '  rm -rf "$task_run_dir/iter"\n'
    + '  if [[ -d "$task_dir/.iterations" ]]; then\n'
    + '    latest_iter="$(ls -1t "$task_dir/.iterations" | head -1)"\n'
    + '    if [[ -n "$latest_iter" ]]; then\n'
    + '      mv "$task_dir/.iterations/$latest_iter" "$task_run_dir/iter" 2>/dev/null || true\n'
    + "    fi\n"
    + "  fi\n"
    + "\n"
    + '  if [[ -x "$task_dir/grade.sh" ]]; then\n'
    + '    if "$task_dir/grade.sh" "$task_run_dir/iter" > "$task_run_dir/grade.txt" 2>&1; then\n'
    + '      n_pass=$((n_pass + 1)); grade_status="pass"\n'
    + "    else\n"
    + '      grade_status="fail"\n'
    + "    fi\n"
    + "  else\n"
    + '    grade_status="missing"\n'
    + "  fi\n"
    + "\n"
    + '  tok=0\n'
    + '  if [[ -s "$task_run_dir/cycle-summary.json" ]]; then\n'
    + '    tok=$(python3 -c "import json; print(int(json.load(open('"'"'"$task_run_dir/cycle-summary.json"'"'"' )).get('"'"'tokens'"'"',0) or 0))" 2>/dev/null || echo 0)\n'
    + "  fi\n"
    + '  total_tokens=$((total_tokens + tok))\n'
    + '  results+=("{\\"task\\":\\"$task\\",\\"status\\":\\"$grade_status\\",\\"tokens\\":$tok}")\n'
    + "done\n"
    + "\n"
    + 'pass_rate=$(python3 -c "print(round($n_pass / max($n_total, 1), 4))")\n'
    + "python3 -c \"\n"
    + "import json\n"
    + "score = {\n"
    + "    'cycle': '$CYCLE',\n"
    + "    'n_pass': $n_pass,\n"
    + "    'n_total': $n_total,\n"
    + "    'pass_rate': $pass_rate,\n"
    + "    'total_tokens': $total_tokens,\n"
    + "}\n"
    + 'print(json.dumps(score, indent=2))\n'
    + "\" > \"$SCORE_FILE\"\n"
    + 'cat "$SCORE_FILE"\n'
)

